const items = $input.all();

const urls = items.map(item => item.json.video.url);

return [
  {
    json: {
      urls: urls
    }
  }
];

const allItems = $input.all();
let results = [];

for (let i = 0; i < allItems.length; i++) {
  const item = allItems[i];

  // Ensure the binary property 'data' exists
  if (item.binary && item.binary.data) {
    try {
      // 1. Use n8n helper to get the buffer correctly
      const buffer = await this.helpers.getBinaryDataBuffer(i, 'data');

      // 2. Convert buffer to a UTF-8 string
      const textContent = buffer.toString('utf-8');

      // 3. Parse the string into a JSON object
      const jsonContent = JSON.parse(textContent);

      results.push({
        json: jsonContent
      });
    } catch (error) {
      results.push({
        json: { 
          error: "Parsing Failed", 
          message: error.message,
          itemIndex: i
        }
      });
    }
  }
}

return results;

const name = $json.name;

const match = name.match(/shotno_(\d+)/);

return {
  json: {
    ...$json,
    shot_num: parseInt(match[1])
  }
};

